1	import { describe, it, expect } from "vitest";
2	import { execute } from "./mars-rover.js";
3	
4	describe("Mars Rover", () => {
5	  it("should return initial position and heading when given no commands", () => {
6	    expect(execute("")).toBe("0:0:N");
7	  });
8	  it("should rotate left from N to W", () => {
9	    expect(execute("L")).toBe("0:0:W");
10	  });
11	  it("should rotate right from N to E", () => {
12	    expect(execute("R")).toBe("0:0:E");
13	  });
14	  it("should move forward facing N by incrementing y", () => {
15	    expect(execute("F")).toBe("0:1:N");
16	  });
17	  it("should move forward facing E by incrementing x", () => {
18	    expect(execute("RF")).toBe("1:0:E");
19	  });
20	  it("should move forward facing S by decrementing y", () => {
21	    expect(execute("RRF")).toBe("0:-1:S");
22	  });
23	  it.todo("should move forward facing W by decrementing x");
24	  it.todo("should rotate left through full cycle (N->W->S->E->N)");
25	  it.todo("should rotate right through full cycle (N->E->S->W->N)");
26	  it.todo("should execute a sequence of mixed commands");
27	});
