1	type Heading = "N" | "E" | "S" | "W";
2	
3	type Rover = {
4	  x: number;
5	  y: number;
6	  heading: Heading;
7	};
8	
9	const INITIAL_ROVER: Rover = { x: 0, y: 0, heading: "N" };
10	
11	const LEFT_OF: Record<Heading, Heading> = {
12	  N: "W",
13	  W: "S",
14	  S: "E",
15	  E: "N",
16	};
17	
18	const RIGHT_OF: Record<Heading, Heading> = {
19	  N: "E",
20	  E: "S",
21	  S: "W",
22	  W: "N",
23	};
24	
25	const FORWARD_DELTA: Record<Heading, { dx: number; dy: number }> = {
26	  N: { dx: 0, dy: 1 },
27	  E: { dx: 1, dy: 0 },
28	  S: { dx: 0, dy: -1 },
29	  W: { dx: -1, dy: 0 },
30	};
31	
32	const applyCommand = (rover: Rover, command: string): Rover => {
33	  if (command === "L") return { ...rover, heading: LEFT_OF[rover.heading] };
34	  if (command === "R") return { ...rover, heading: RIGHT_OF[rover.heading] };
35	  if (command === "F") {
36	    const { dx, dy } = FORWARD_DELTA[rover.heading];
37	    return { ...rover, x: rover.x + dx, y: rover.y + dy };
38	  }
39	  return rover;
40	};
41	
42	const formatRover = (rover: Rover): string =>
43	  `${rover.x}:${rover.y}:${rover.heading}`;
44	
45	export function execute(commands: string): string {
46	  const finalRover = commands
47	    .split("")
48	    .reduce(applyCommand, INITIAL_ROVER);
49	  return formatRover(finalRover);
50	}
